// Exact behaviour: replace each element x[i] with the minimum value
// from indices 0 through i (inclusive)
// This hand‑rolled loop is equivalent to std::inclusive_scan with a
// min operation and uses a single pass with a running minimum.
// It exposes the inner loop to the compiler as a simple arithmetic
// sequence that can be fully vectorised / inlined, giving better
// performance on large data sets and allowing the compiler to avoid
// any of the overhead from the generic algorithm interface.

inline void partialMinimums(std::vector<float>& x)
{
    if (x.empty()) return;

    const float inf = std::numeric_limits<float>::max();
    float current_min = inf;

    // Pointer access to avoid vector bounds checks and allow
    // optimization such as loop‑unrolling and SIMD.
    float* data = x.data();
    const std::size_t n = x.size();

    for (std::size_t i = 0; i < n; ++i) {
        // Update current minimum and store it back.
        current_min = (data[i] < current_min) ? data[i] : current_min;
        data[i] = current_min;
    }
}
