/* Return the largest sum of any contiguous subarray in the vector x.
   Implements Kadane's algorithm, which runs in O(n) time.
   The algorithm keeps track of the maximum subarray ending at each
   position and the overall maximum achieved so far.  The behaviour
   (including the return value for an all-negative input) matches the
   original nested‑loop implementation. */
int maximumSubarray(std::vector<int> const& x)
{
    if (x.empty()) return 0;               // maintain trivial case

    int max_ending_here = x[0];
    int max_so_far = x[0];

    for (std::size_t i = 1; i < x.size(); ++i)
    {
        int v = x[i];
        // choose whether to extend the current subarray or start a new one
        if (max_ending_here > 0)
            max_ending_here += v;
        else
            max_ending_here = v;

        if (max_ending_here > max_so_far)
            max_so_far = max_ending_here;
    }

    return max_so_far;
}
