/* Return the sum of the minimum value at each index of vectors x and y for all indices.
   i.e. sum = min(x_0, y_0) + min(x_1, y_1) + min(x_2, y_2) + ...
*/
int64_t sumOfMinimumElements(const std::vector<int64_t>& x, const std::vector<int64_t>& y) {
    const std::size_t n = x.size();
    // safe guard: if sizes mismatch just treat missing as infinite
    std::size_t m = std::min(n, y.size());
    int64_t sum = 0;
#pragma omp parallel for reduction(+:sum)
    for (std::size_t i = 0; i < m; ++i) {
        sum += std::min(x[i], y[i]);
    }
    // If one vector is longer, add the remaining elements (since min with +∞ => element itself)
    if (n > m) {
#pragma omp parallel for reduction(+:sum)
        for (std::size_t i = m; i < n; ++i) {
            sum += x[i];
        }
    } else if (y.size() > m) {
#pragma omp parallel for reduction(+:sum)
        for (std::size_t i = m; i < y.size(); ++i) {
            sum += y[i];
        }
    }
    return sum;
}
