        std::array<size_t, alphabet> &local_bins = local[tid];

        #pragma omp for schedule(static)
        for (size_t i = 0; i < n; ++i) {
            const unsigned char c = s[i][0];
            // Assuming guaranteed lower‑case; unused branch can be compiler‑elided
            const int idx = c - 'a';
            if (idx >= 0 && idx < alphabet)
                ++local_bins[idx];
        }
    }

    // Merge local results into global bins
    for (int t = 0; t < nthreads; ++t) {
        const auto& lb = local[t];
        for (int i = 0; i < alphabet; ++i)
            bins[i] += lb[i];
    }
