/* Count the number of pixels in image with each grayscale intensity.
   The vector `image` is a grayscale image with values 0-255.
   Store the results in `bins`.
   Example:

   input: image=[2, 116, 201, 11, 92, 92, 201, 4, 2]
   output: [0, 0, 2, 0, 1, ...]
*/
void pixelCounts(std::vector<int> const& image, std::array<size_t, 256> &bins) {
    // Zero the result array
    std::fill(bins.begin(), bins.end(), 0);

    // Number of possible pixel values
    constexpr int HIST_SIZE = 256;

    // Determine number of threads
    int nthreads = omp_get_max_threads();

    // Allocate thread‑local histograms
    std::vector<std::array<size_t, HIST_SIZE>> local_bins(nthreads);
    for (int t = 0; t < nthreads; ++t) {
        local_bins[t].fill(0);
    }

    // Parallel histogramming
    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        auto &local = local_bins[tid];

        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < image.size(); ++i) {
            // image values are guaranteed to be in 0..255
            ++local[image[i]];
        }
    }

    // Reduce thread‑local histograms into the output array
    for (int t = 0; t < nthreads; ++t) {
        const auto &local = local_bins[t];
        for (int v = 0; v < HIST_SIZE; ++v) {
            bins[v] += local[v];
        }
    }
}
