/*  Fastest stack‑based DFS using a plain byte visited array
 *  and a non‑recursive algorithm.
 *  The function returns the size of the largest connected component
 *  in the graph described by the NxN adjacency matrix `A` (row‑major).
 */
int largestComponent(const std::vector<int>& A, size_t N)
{
    /*  Using a byte per vertex is faster than std::vector<bool>.
     *  It avoids bit‑packing overhead and allows direct access.        */
    std::vector<uint8_t> visited(N, 0);
    int maxSize = 0;

    std::stack<int> st;
    for (int start = 0; start < static_cast<int>(N); ++start)
    {
        if (visited[start]) continue;

        /*  Start a new component */
        int curSize = 0;
        st.push(start);
        visited[start] = 1;

        while (!st.empty())
        {
            int v = st.top(); st.pop();
            ++curSize;

            /*  Scan row `v`. The layout is row‑major, so all
             *  neighbours of `v` lie in the consecutive slice */
            const int base = static_cast<int>(v) * static_cast<int>(N);
            for (int w = 0; w < static_cast<int>(N); ++w)
            {
                if (A[base + w] && !visited[w])
                {
                    visited[w] = 1;
                    st.push(w);
                }
            }
        }
        maxSize = std::max(maxSize, curSize);
    }
    return maxSize;
}
