    for (auto& b : bins) b = 0;

    // Work in chunks that fit in a cache line to minimise false sharing.
    const std::size_t chunk_size = 256;               // tweakable
    const std::size_t n = x.size();

    #pragma omp parallel
    {
        std::array<size_t,4> local = {0,0,0,0};

        #pragma omp for schedule(static,chunk_size)
        for (std::size_t i = 0; i < n; ++i)
        {
            // Compute the fractional part in a branchless way
            double f = x[i] - std::floor(x[i]);   // fractional part in [0,1)
            // Scale to [0,4) and cast to int – this is equivalent to
            // floor(f*4) but avoids a separate multiplication.
            int bucket = static_cast<int>(f * 4.0);

            // Clamp in case of round‑off errors (should never happen)
            if (bucket < 0) bucket = 0;
            if (bucket > 3) bucket = 3;

            ++local[bucket];
        }

        // Merge local counts into the global bins
        #pragma omp critical
        {
            for (int i = 0; i < 4; ++i)
                bins[i] += local[i];
        }
    }
