#include <omp.h>

/* ------------------------------------------------------------------
   COOElement: sparse matrix entry in COO format
-------------------------------------------------------------------*/
struct COOElement {
   std::size_t row, column;
   double value;
};

/* ------------------------------------------------------------------
   luFactorize: LU factorization of an N×N sparse matrix A stored
   in COO format. L is unit lower‑triangular, U is upper‑triangular.
   The result is returned in the flat arrays L and U (row‑major).
   ------------------------------------------------------------------*/
inline void luFactorize(std::vector<COOElement> const& A,
                        std::vector<double>&      L,
                        std::vector<double>&      U,
                        std::size_t               N)
{
    /* Initialise output arrays */
    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    /* Build a dense copy of A using a flat array for speed */
    std::vector<double> Afull(N * N, 0.0);
    for (auto const& e : A)
        Afull[e.row * N + e.column] = e.value;

    /* LU factorisation ------------------------------------------------*/
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        /* Compute the i‑th row of U first (j >= i) */
        for (std::size_t j = i; j < N; ++j) {
            double u = Afull[i * N + j];
            for (std::size_t k = 0; k < i; ++k)
                u -= L[i * N + k] * U[k * N + j];
            U[i * N + j] = u;
        }

        /* Compute the i‑th row of L (j < i) */
        for (std::size_t j = 0; j < i; ++j) {
            double l = Afull[i * N + j];
            for (std::size_t k = 0; k < j; ++k)
                l -= L[i * N + k] * U[k * N + j];
            l /= U[j * N + j];
            L[i * N + j] = l;
        }

        /* Unit diagonal of L */
        L[i * N + i] = 1.0;
    }
}
