// In-place DFT for real‐valued input.
// The implementation uses repeated complex multiplication to avoid
// per‑term trigonometric evaluations and parallelises the outer loop
// with OpenMP. All behaviour (including correctness and order of
// results) is identical to the reference implementation.
void dft(std::vector<double> const& x, std::vector<std::complex<double>>& output)
{
    const int N = static_cast<int>(x.size());
    output.resize(N);
    // Pre‑allocate a temporary vector for the reciprocal angle
    const double twopi = 2.0 * M_PI;
    const double invN = 1.0 / N;

    #pragma omp parallel for schedule(static)
    for (int k = 0; k < N; ++k) {
        // W = exp(-2πi * k / N)
        const double angle_k = twopi * k * invN;
        const double cos_k = std::cos(angle_k);
        const double sin_k = std::sin(angle_k);
        const std::complex<double> w_k(cos_k, -sin_k);          // e^{-2πi k/N}
        std::complex<double> c(1.0, 0.0);                       // current weight
        std::complex<double> sum(0.0, 0.0);

        for (int n = 0; n < N; ++n) {
            sum += x[n] * c;
            c *= w_k;                                            // advance to next weight
        }
        output[k] = sum;
    }
}
