/*  Count connected components in an undirected graph given its
    adjacency matrix (row‑major). Parallelised with OpenMP while
    keeping the original behaviour and return value.     */
inline void
dfs_iterative(std::vector<int> const& A, int start, size_t N,
              std::vector<std::atomic<bool>>& visited)
{
    std::stack<int> st;
    st.push(start);
    visited[start] = true;

    while (!st.empty()) {
        int v = st.top();
        st.pop();

        /* jump over row of v */
        const int* row = A.data() + v * N;
        for (size_t i = 0; i < N; ++i) {
            if (row[i] == 1) {
                bool expected = false;
                /* try to claim vertex i */
                if (visited[i].compare_exchange_strong(expected, true,
                        std::memory_order_acq_rel)) {
                    st.push(i);
                }
            }
        }
    }
}

int componentCount(std::vector<int> const& A, size_t N)
{
    /* Use atomic<bool> to avoid data races when multiple threads
       inspect/modify visited. */
    std::vector<std::atomic<bool>> visited(N);
    for (size_t i = 0; i < N; ++i) visited[i] = false;

    int count = 0;

#pragma omp parallel for schedule(static) reduction(+:count)
    for (int i = 0; i < static_cast<int>(N); ++i) {
        bool expected = false;
        /* Only one thread wins the test for a given vertex */
        if (visited[i].compare_exchange_strong(expected, true,
                std::memory_order_acq_rel)) {
            /* This thread owns the component starting at i */
            dfs_iterative(A, i, N, visited);
            ++count;
        }
    }
    return count;
}
