/* Compute one iteration of a 3‑point 1‑D Jacobi stencil on `input`.
   Each element of `input` is averaged with its two neighbours and
   stored in the corresponding element of `output`.  A padding of zero
   is used when a neighbour lies outside the boundary.
   The implementation preserves the exact numerical behaviour
   of the original code while aiming for the best possible performance
   on a modern x86‑64 machine with up to 8 threads.
*/
inline void jacobi1D(std::vector<double> const& input,
                     std::vector<double> &output)
{
    const size_t n = input.size();
    if (n == 0) return;

    // For maximum cache locality use raw pointers.
    const double *in  = input.data();
    double       *out = output.data();

    /* OpenMP parallelisation */
#pragma omp parallel for schedule(static) if(n > 1024)
    for (size_t i = 0; i < n; ++i) {
        double left  = (i > 0)     ? in[i - 1] : 0.0;
        double right = (i + 1 < n) ? in[i + 1] : 0.0;
        out[i] = (left + in[i] + right) / 3.0;
    }
