    const std::size_t n = points.size();
    if(n < 3) return 0.0;

    double minArea = std::numeric_limits<double>::max();

    // Use atomic for minimal area update.  The cost of atomic operations is
    // small compared with the cubic work for N > 1000 and eliminates the
    // need for explicit locks.
    std::atomic<double> minAtom(minArea);

    #pragma omp parallel for schedule(dynamic, 256) collapse(2) reduction(min:minArea)
    for (std::size_t i = 0; i < n-2; ++i){
        for (std::size_t j = i+1; j < n-1; ++j){
            const Point &pi = points[i], &pj = points[j];
            for (std::size_t k = j+1; k < n; ++k){
                double area = tri_area(pi, pj, points[k]);
                #pragma omp atomic min
                minAtom = std::min(minAtom.load(), area);
            }
        }
    }
    return minAtom.load();
