#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Exact‑behaviour solver for ax=b with a sparse COO matrix.
   The implementation keeps the same algorithmic logic (partial
   pivoting, Gaussian elimination, back‑substitution) but leverages
   OpenMP for parallel inner‑row operations.  The dense matrix
   representation is retained because the input format is COO
   and converting to CSR would change the guarantee that the
   function produces exactly the same numeric result as the
   original (which is agnostic to the storage format).
*/
void solveLinearSystem(const std::vector<COOElement>& A,
                       const std::vector<double>& b,
                       std::vector<double>& x,
                       size_t N)
{
    // Allocate dense matrix
    std::vector<std::vector<double>> mat(N, std::vector<double>(N, 0.0));
    // Copy RHS
    std::vector<double> rhs = b;
    // Fill dense matrix from COO
    for (const auto& e : A) {
        mat[e.row][e.column] = e.value;
    }
    // Ensure x has correct size
    x.assign(N, 0.0);

    // ----- Gaussian elimination with partial pivoting -----
    for (size_t i = 0; i < N; ++i) {
        // --- Partial pivoting (parallel max search) ---
        size_t maxRow = i;
        double maxVal = std::abs(mat[i][i]);

#pragma omp parallel
        {
            size_t localMaxRow = i;
            double localMaxVal = maxVal;
#pragma omp for nowait
            for (size_t k = i + 1; k < N; ++k) {
                double val = std::abs(mat[k][i]);
                if (val > localMaxVal) {
                    localMaxVal = val;
                    localMaxRow = k;
                }
            }
#pragma omp critical
            {
                if (localMaxVal > maxVal) {
                    maxVal = localMaxVal;
                    maxRow = localMaxRow;
                }
            }
        }

        // Swap rows in matrix and RHS
        if (maxRow != i) {
            std::swap(mat[maxRow], mat[i]);
            std::swap(rhs[maxRow], rhs[i]);
        }

        // --- Eliminate rows below pivot (parallel) ---
#pragma omp parallel for
        for (size_t k = i + 1; k < N; ++k) {
            double c = -mat[k][i] / mat[i][i];
            for (size_t j = i; j < N; ++j) {
                if (i == j) {
                    mat[k][j] = 0.0;
                } else {
                    mat[k][j] += c * mat[i][j];
                }
            }
            rhs[k] += c * rhs[i];
        }
    }

    // ----- Back substitution (serial) -----
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        x[i] = rhs[i] / mat[i][i];
        for (int k = i - 1; k >= 0; --k) {
            rhs[k] -= mat[k][i] * x[i];
        }
    }
}
