#pragma once
#include <cstdint>
#include <vector>
#include <omp.h>

/* ------------------------------------------------------------------
   Compute the prefix sum array of the vector `x` (inclusive) and
   return its sum.

   Example:
     input:  [-7, 2, 1, 9, 4, 8]
     prefix: [-7,-5,-4, 5, 9,17]
     output:  15
   ------------------------------------------------------------------ */
inline std::int64_t sumOfPrefixSum(const std::vector<std::int64_t> &x)
{
    const std::size_t n = x.size();
    if (n == 0) return 0;

    std::vector<std::int64_t> prefixSum(n);

    /* --------- parallel inclusive scan (prefix sum) ------------- */
    const int numThreads = omp_get_max_threads();
    std::vector<std::int64_t> blockSum(numThreads, 0);

    // Step 1: each thread computes local prefix for its chunk
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const std::size_t chunk = (n + numThreads - 1) / numThreads;
        const std::size_t start = std::size_t(tid) * chunk;
        const std::size_t end   = std::min(start + chunk, n);

        if (start >= end) return; // empty chunk

        std::int64_t localSum = x[start];
        prefixSum[start] = localSum;
        for (std::size_t i = start + 1; i < end; ++i) {
            localSum += x[i];
            prefixSum[i] = localSum;
        }
        blockSum[tid] = localSum;               // last value of block
    }

    // Step 2: prefix sum of block sums (serial part)
    for (int i = 1; i < numThreads; ++i)
        blockSum[i] += blockSum[i-1];

    // Step 3: add block offsets to each element except the first block
    #pragma omp parallel for schedule(static)
    for (int i = 1; i < numThreads; ++i) {
        const std::size_t chunk = (n + numThreads - 1) / numThreads;
        const std::size_t start = std::size_t(i) * chunk;
        const std::size_t end   = std::min(start + chunk, n);
        const std::int64_t offset = blockSum[i-1];
        for (std::size_t j = start; j < end; ++j)
            prefixSum[j] += offset;
    }

    /* --------- parallel sum of the prefix array --------------- */
    std::int64_t total = 0;
    #pragma omp parallel for reduction(+:total)
    for (std::size_t i = 0; i < n; ++i)
        total += prefixSum[i];

    return total;
}
