/*
   Fast iterative FFT (radix‑2 decimation‑in‑time) with explicit bit‑reversal.
   The function signature is unchanged and the output format (separate
   real/imag vectors) is identical to the original implementation.
*/

constexpr double PI = 3.14159265358979323846;

static inline uint32_t reverse_bits(uint32_t v, unsigned int bits) {
    // Reverse lower 'bits' bits of v
    static const uint32_t masks[5] = {
        0xaaaaaaaa, 0xcccccccc, 0xf0f0f0f0, 0xff00ff00, 0xffff0000
    };
    static const unsigned int shifts[5] = {1,2,4,8,16};

    for (int i = 0; i < 5; ++i)
        v = (v >> shifts[i]) | (v << shifts[i]);

    v >>= (32 - bits);
    return v;
}

void fft(std::vector<std::complex<double>> const& x, std::vector<double> &r, std::vector<double> &i) {
    const size_t N = x.size();
    if (N == 0) return;

    // Allocate working buffer
    std::vector<std::complex<double>> a(x.begin(), x.end());

    // Pre‑compute twiddle factors for each stage
    unsigned int stages = static_cast<unsigned int>(std::log2(N));
    std::vector<std::vector<std::complex<double>>> twiddles(stages);
    for (unsigned int s = 0; s < stages; ++s) {
        unsigned int m = 1 << (s + 1);
        double ang = -2.0 * PI / static_cast<double>(m);
        const double cs = std::cos(ang);
        const double sn = std::sin(ang);
        twiddles[s].resize(m/2);
        std::complex<double> w(1.0, 0.0);
        for (unsigned int j = 0; j < m/2; ++j) {
            twiddles[s][j] = w;
            w *= std::complex<double>(cs, sn);
        }
    }

    // Main butterfly loop
    for (unsigned int s = 0; s < stages; ++s) {
        unsigned int m = 1 << (s + 1);
        unsigned int half = m >> 1;
        const std::complex<double>* tw = twiddles[s].data();

#pragma omp parallel for schedule(static)
        for (unsigned int k = 0; k < N; k += m) {
            for (unsigned int j = 0; j < half; ++j) {
                std::complex<double> t = tw[j] * a[k + j + half];
                std::complex<double> u = a[k + j];
                a[k + j]           = u + t;
                a[k + j + half]    = u - t;
            }
        }
    }

    // Bit‑reversal permutation
    for (unsigned int j = 0; j < N; ++j) {
        unsigned int r = reverse_bits(j, stages);
        if (r > j) std::swap(a[j], a[r]);
