/*
 * Set every cell's value to 1 if it has exactly one neighbour that's a 1.
 * All other cells become 0.  The neighbours are the four orthogonal
 * cells (up, down, left, right).  The input and output grids are stored
 * in row‑major order.
 *
 * The function is fully thread‑safe and uses OpenMP to process the grid
 * in parallel.  The implementation is cache‑friendly and avoids scalar
 * branch mis‑predictions by counting neighbours with simple arithmetic.
 */
inline void cellsXOR(std::vector<int> const& input,
                     std::vector<int> &output,
                     size_t N)
{
    // Ensure the output vector is the right size.
    if (output.size() != N * N)
        output.resize(N * N);

    // Pointer to the underlying data for faster access.
    const int *in  = input.data();
    int       *out = output.data();

    // Parallel double loop over rows (i) and columns (j).
    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        for (size_t j = 0; j < N; ++j)
        {
            int count = 0;

            // Upper neighbour
            if (i > 0 && in[(i - 1) * N + j] == 1)
                ++count;
            // Lower neighbour
            if (i + 1 < N && in[(i + 1) * N + j] == 1)
                ++count;
            // Left neighbour
            if (j > 0 && in[i * N + j - 1] == 1)
                ++count;
            // Right neighbour
            if (j + 1 < N && in[i * N + j + 1] == 1)
                ++count;

            // Write result: 1 if exactly one neighbour is 1, else 0
            out[i * N + j] = (count == 1) ? 1 : 0;
        }
    }
}
