#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstdint>
#include <omp.h>

/*  Parallel radix‑2 in‑place FFT.
    The function keeps the exact numerical behaviour of the
    original implementation (except for very tiny round‑off
    differences that are inevitable when the order of operations
    changes).  It assumes that the input length is a power of two.
*/
inline void fft(const std::vector<std::complex<double>>& x,
                std::vector<std::complex<double>>& output)
{
    const std::size_t N = x.size();
    output = x;                            // copy data

    /* pre‑compute twiddle factors for all stages */
    std::vector<std::complex<double>> twiddles;
    twiddles.reserve(N/2);
    for (std::size_t k = 1; k < N; k <<= 1) {
        const double angle = -M_PI / k;
        for (std::size_t j = 0; j < k; ++j)
            twiddles.push_back(std::complex<double>(std::cos(angle * j), std::sin(angle * j)));
    }

    /* iterative radix‑2 butterfly */
    std::size_t stride = 1;      // 2^stage
    std::size_t t_index = 0;     // index into twiddle table
    for (std::size_t stage = 0; stage < static_cast<std::size_t>(std::log2(N)); ++stage, stride <<= 1) {
        const std::size_t half = stride;
        const std::size_t tw_len = half;
#pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < N; i += stride << 1) {
            std::size_t idx = 0;
            for (std::size_t j = 0; j < half; ++j, ++idx) {
                std::size_t a = i + j;
                std::size_t b = a + half;
                const std::complex<double> w = twiddles[t_index + idx];
                const std::complex<double> t = output[a] - output[b];
                output[a] += output[b];
                output[b]  = t * w;
            }
        }
        t_index += tw_len;
    }

    /* bit‑reversal permutation */
    const std::size_t logN = static_cast<std::size_t>(std::log2(N));
    for (std::size_t i = 0; i < N - 1; ++i) {
        std::size_t j = i ^ (i & 1);
        for (std::size_t shift = 2; shift <= logN; shift <<= 1)
            j ^= (i & shift) >> 1;
        if (j > i) std::swap(output[i], output[j]);
    }
}
