#pragma once
#include <vector>
#include <algorithm>
#include <omp.h>

struct Point {
    double x, y;
};

/*
 * Compute the convex hull of the given set of points using the
 * monotone chain algorithm (Graham scan). The result is stored in
 * `hull`; the order is counter‑clockwise starting from the left‑most
 * point.
 */
inline double cross(const Point& a, const Point& b, const Point& c) {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

void convexHull(const std::vector<Point>& points, std::vector<Point>& hull) {
    const std::size_t n = points.size();
    if (n < 3) {                  // too few points to form a polygon
        hull = points;
        return;
    }

    // Sort points lexicographically (x, then y).  The copy is needed
    // so that the input vector can remain unchanged.
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(), [](const Point& a, const Point& b) {
        return (a.x < b.x) || (a.x == b.x && a.y < b.y);
    });

    // Reserve twice the number of points (upper + lower hull, without last point duplication).
    std::vector<Point> temp(2 * n);
    int k = 0;                     // number of points currently in temp

    // Build lower hull
    for (std::size_t i = 0; i < n; ++i) {
        while (k >= 2 && cross(temp[k - 2], temp[k - 1], sorted[i]) <= 0.0)
            --k;                   // pop the last point
        temp[k++] = sorted[i];
    }

    // Build upper hull
    const int t = k + 1;           // starting index for upper hull
    for (std::size_t i = n; i-- > 0; ) {
        while (k >= t && cross(temp[k - 2], temp[k - 1], sorted[i]) <= 0.0)
            --k;
        temp[k++] = sorted[i];
    }

    // Remove duplicate last point (the first point is repeated)
    temp.resize(k - 1);
    hull.swap(temp);
}
