#include <omp.h>

struct Point {
    double x, y;
};

namespace detail {
    // Cross product of OA x OB
    inline double cross(const Point& a, const Point& b, const Point& c) noexcept {
        return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
    }
    // Euclidean distance without pow/sqrt overhead
    inline double dist(const Point& a, const Point& b) noexcept {
        double dx = a.x - b.x;
        double dy = a.y - b.y;
        return std::sqrt(dx * dx + dy * dy);
    }
}

// Return the perimeter of the smallest convex polygon that contains all the points in the vector points.
inline double convexHullPerimeter(const std::vector<Point>& points) {
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    // Copy points for sorting
    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end(),
              [](const Point& a, const Point& b) noexcept {
                  return (a.x < b.x) || (a.x == b.x && a.y < b.y);
              });

    // Build hull (Monotone Chain)
    std::vector<Point> hull;
    hull.reserve(2 * n);

    // Lower hull
    for (const auto& p : pts) {
        while (hull.size() >= 2 &&
               detail::cross(hull[hull.size() - 2], hull.back(), p) <= 0.0) {
            hull.pop_back();
        }
        hull.push_back(p);
    }

    // Upper hull
    std::size_t lowerSize = hull.size();
    for (std::size_t i = n - 1; i > 0; --i) {
        const auto& p = pts[i - 1];
        while (hull.size() > lowerSize &&
               detail::cross(hull[hull.size() - 2], hull.back(), p) <= 0.0) {
            hull.pop_back();
        }
        hull.push_back(p);
    }

    // Last point is same as first one, drop it
    if (!hull.empty()) hull.pop_back();

    const std::size_t m = hull.size();
    if (m < 3) return 0.0;

    // Parallel perimeter computation
    double perimeter = 0.0;
    #pragma omp parallel for reduction(+:perimeter)
    for (std::size_t i = 0; i < m; ++i) {
        const std::size_t j = (i + 1) % m;
        perimeter += detail::dist(hull[i], hull[j]);
    }
    return perimeter;
}
