/* Compute the reverse prefix sum of the vector `x` into `output`.
 *
 *  Examples:
 *      input:  [1, 7, 4, 6, 6, 2]
 *      output: [2, 8, 14, 18, 25, 26]
 *
 *      input:  [3, 3, 7, 1, -2]
 *      output: [-2, -1, 6, 9, 12]
 *
 *  The implementation below avoids allocating an intermediate reversed
 *  copy of the input.  Instead the computation is carried out in two
 *  parallel passes:  first the sums of blocks of the array are
 *  accumulated, the second pass adds the block sums to the per‑block
 *  working results.  This preserves the behaviour of the original
 *  sequential solution while exploiting the available 8 hardware
 *  threads.
 */
inline void reversePrefixSum(const std::vector<int>& x, std::vector<int>& output)
{
    const std::size_t n = x.size();
    if (n == 0) { output.clear(); return; }

    output.resize(n);

    /* 1) Split the work in chunks.  The chunk size is chosen such that
     *    each thread receives roughly the same amount of data.
     */
    const std::size_t chunk = (n + 7) / 8;                 // 8 threads maximum
    const std::size_t blockCnt = (n + chunk - 1) / chunk; // ceiling division
    std::vector<long long> blockSum(blockCnt, 0);          // 64‑bit to avoid overflow

    /* 2) First pass: each thread computes the sum of its chunk
     *    (in reverse order) and stores it in blockSum.
     */
    #pragma omp parallel for schedule(static)
    for (std::size_t b = 0; b < blockCnt; ++b)
    {
        const std::size_t start = b * chunk;
        const std::size_t end   = std::min(start + chunk, n);
        long long sum = 0;
        for (std::size_t i = start; i < end; ++i)
            sum += x[n - 1 - i];           // reverse index
        blockSum[b] = sum;
    }

    /* 3) Compute the prefix sums of blockSum in reverse order */
    std::vector<long long> blockPrefix(blockCnt, 0);
    long long acc = 0;
    for (std::size_t b = 0; b < blockCnt; ++b)
    {
        blockPrefix[b] = acc;
        acc += blockSum[b];
    }

    /* 4) Second pass: write the output, adding the offset from
     *    preceding blocks.
     */
    #pragma omp parallel for schedule(static)
    for (std::size_t b = 0; b < blockCnt; ++b)
    {
        const std::size_t start = b * chunk;
        const std::size_t end   = std::min(start + chunk, n);
        long long running = blockPrefix[b];
        for (std::size_t i = start; i < end; ++i)
        {
            running += x[n - 1 - i];
            output[n - 1 - i] = static_cast<int>(running);
        }
    }
}
