#include <cstddef>
#include <immintrin.h>
#include <omp.h>

/* Optimised GEMM: C += A * B
   A (MxK), B (KxN), C (MxN) stored row‑major.
   Uses OpenMP parallelism, loop tiling, and AVX2 intrinsics for best performance
   on modern x86‑64 CPUs. */
inline void gemm(const std::vector<double> &A,
                 const std::vector<double> &B,
                 std::vector<double> &C,
                 const size_t M, const size_t K, const size_t N) {

    // Tile sizes tuned for typical L1/L2 cache latencies
    constexpr size_t TB = 64;   // block size for N and K dimensions
    constexpr size_t TI = 64;   // block size for M dimension

    // Ensure C is zeroed (guaranteed by caller in this harness)
    // Parallel over outer tile of M
    #pragma omp parallel for schedule(static)
    for (size_t ii = 0; ii < M; ii += TI) {
        const size_t imax = std::min(ii + TI, M);

        for (size_t kk = 0; kk < K; kk += TB) {
            const size_t kmax = std::min(kk + TB, K);

            for (size_t jj = 0; jj < N; jj += TB) {
                const size_t jmax = std::min(jj + TB, N);

                // Compute block for rows [ii,imax), cols [jj,jmax)
                for (size_t i = ii; i < imax; ++i) {
                    const double *ai = &A[i * K];
                    double *ci = &C[i * N + jj];

                    for (size_t k = kk; k < kmax; ++k) {
                        const double aik = ai[k];

                        // Vectorised inner loop over N
                        size_t j = jj;
                        for (; j + 4 <= jmax; j += 4) {
                            __m256d vC = _mm256_loadu_pd(&ci[j]);
                            __m256d vB = _mm256_loadu_pd(&B[k * N + j]);
                            vC = _mm256_fmadd_pd(vB, _mm256_set1_pd(aik), vC);
                            _mm256_storeu_pd(&ci[j], vC);
                        }
                        // Handle rest scalar
                        for (; j < jmax; ++j) {
                            ci[j] += aik * B[k * N + j];
                        }
                    }
                }
            }
        }
    }
}
