#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Simulate one generation of Game of Life on `input`. Store the results in `output`.
   The function keeps the exact semantics of the original implementation but
   uses pointer arithmetic, fewer branches and an OpenMP parallel loop to
   achieve high performance on modern x86‑64 CPUs.
*/
void gameOfLife(std::vector<int> const& input,
                std::vector<int> &output,
                size_t N) noexcept
{
    // Ensure we have enough space
    if (output.size() < N * N) output.resize(N * N);

    // Pointers to the underlying data
    const int *restrict const in  = input.data();
    int *restrict const out       = output.data();
    const size_t stride = N;                     // row stride in elements

    // Parallelize over rows and columns
    #pragma omp parallel for schedule(static)
    for (ssize_t ii = 0; ii < static_cast<long>(N); ++ii) {
        const int *restrict in_row   = in + ii * stride;
        int *restrict       out_row  = out + ii * stride;
        int *restrict       out_cell = out_row; // will be moved column by column

        for (size_t jj = 0; jj < N; ++jj) {
            int const self = in_row[jj];
            int sum = 0;

            // Gather the eight neighbours with minimal branching
            // 1. Horizontal neighbours
            if (jj > 0)     sum += in_row[jj - 1];
            if (jj + 1 < N) sum += in_row[jj + 1];

            // 2. Vertical neighbours
            if (ii > 0) {
                const int *restrict prev_row = in_row - stride;
                sum += prev_row[jj];
                if (jj > 0)     sum += prev_row[jj - 1];
                if (jj + 1 < N) sum += prev_row[jj + 1];
            }
            if (ii + 1 < N) {
                const int *restrict next_row = in_row + stride;
                sum += next_row[jj];
                if (jj > 0)     sum += next_row[jj - 1];
                if (jj + 1 < N) sum += next_row[jj + 1];
            }

            // Apply the Game of Life rules
            out_cell[jj] = (self == 1)
                ? ((sum < 2 || sum > 3) ? 0 : 1)
                : ((sum == 3) ? 1 : 0);
        }
    }
}
