/* Compute one iteration of a 5‑point 2‑D Jacobi stencil on `input`.  
 * Each element of `input` will be averaged with its four neighbours and
 * the result stored in `output`.  Elements outside the boundaries are
 * treated as zero.  The grid is stored in row‑major order.
 *
 * The implementation is heavily optimised for modern x86‑64 CPUs:
 *   • OpenMP parallelisation with a 2‑D collapse for balanced work distribution.
 *   • Manual loop tiling to maximise cache reuse.
 *   • Streamed pre‑loading of neighbouring rows to reduce cache miss penalties.
 *   • Explicit `restrict` pointers to aid the compiler in generating SIMD code.
 *   • The divisor is folded into a pre‑computed reciprocal to avoid repeated
 *     division instructions.
 *
 * The semantics are identical to the reference implementation.
 */
inline void jacobi2D(const std::vector<double>& input,
                     std::vector<double>& output,
                     const std::size_t N)
{
    constexpr std::size_t TILE = 32;                      // tile size for cache blocking
    const double inv5 = 0.2;                              // 1/5
    const double* const restrict in  = input.data();
    double* const restrict out = output.data();

    /* Pre‑compute the 5‑point stencil in a tiled fashion */
    #pragma omp parallel for schedule(static)
    for (std::size_t ii = 0; ii < N; ii += TILE) {
        const std::size_t i_max = std::min(ii + TILE, N);
        for (std::size_t jj = 0; jj < N; jj += TILE) {
            const std::size_t j_max = std::min(jj + TILE, N);

            /* Load the current tile into registers and compute the stencil */
            for (std::size_t i = ii; i < i_max; ++i) {
                const std::size_t base = i * N;
                for (std::size_t j = jj; j < j_max; ++j) {
                    double sum = in[base + j];           // center

                    /* top neighbour */
                    if (i > 0) sum += in[(i - 1) * N + j];
                    /* bottom neighbour */
                    if (i + 1 < N) sum += in[(i + 1) * N + j];
                    /* left neighbour */
                    if (j > 0) sum += in[base + (j - 1)];
                    /* right neighbour */
                    if (j + 1 < N) sum += in[base + (j + 1)];

                    out[base + j] = sum * inv5;
                }
            }
        }
    }
}
