/*
 * Return the index of the value in the vector `x` that is closest to the math constant PI.
 * Use M_PI for the value of PI.
 * Example:
 *   input: [9.18, 3.05, 7.24, 11.3, -166.49, 2.1]
 *   output: 1
 */
static inline size_t findClosestToPi(const std::vector<double>& x) noexcept {
    size_t best_index = 0;
    double best_diff   = std::abs(x[0] - M_PI);

    // Parallel reduction over all elements except the first one
    #pragma omp parallel
    {
        size_t local_index = best_index;
        double  local_diff = best_diff;

        #pragma omp for
        for (size_t i = 1; i < x.size(); ++i) {
            double diff = std::abs(x[i] - M_PI);
            if (diff < local_diff) {
                local_diff  = diff;
