/*
 * Compute the rank of each element in a floating‑point array.
 * Rank is defined as the position of the element in the sorted array,
 * with ties broken by the original index order (stable sort).
 *
 * Parameters
 * ----------
 * x         : input vector of floats (must not be modified)
 * ranks_    : output vector of the same size as `x`.
 *             After the call, ranks_[i] holds the rank of x[i].
 */
inline void ranks(const std::vector<float> &x, std::vector<std::size_t> &ranks_) {
    const std::size_t n = x.size();
    if (n == 0) return;

    // Allocate temporary array for indices and initialise it 0,1,2,...
    std::vector<std::size_t> indices(n);
    std::iota(indices.begin(), indices.end(), 0);

    // Stable sort the indices according to the corresponding values in x.
    // Using a parallel sort implementation is unnecessary for 8 threads
    // on typical workloads and adds complexity, so the standard sort is fine.
    std::stable_sort(indices.begin(), indices.end(),
                     [&x](std::size_t i, std::size_t j) { return x[i] < x[j]; });

    // Write the ranks back in the original order.
    // Parallelize the write step for extra speed on large vectors.
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(n); ++i) {
        ranks_[indices[i]] = static_cast<std::size_t>(i);
    }
}
