struct Point {
    double x, y;
};

/* -------------------------------------------------------------
   Compute the Euclidean distance between two points.
   ------------------------------------------------------------- */
inline double dist(const Point& a, const Point& b)
{
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return std::hypot(dx, dy);          // fast, single sqrt
}

/* -------------------------------------------------------------
   Return the distance between the closest two points in the
   vector points. Uses a divide‑and‑conquer algorithm with
   an OpenMP parallelized outer loop for the base cases.
   ------------------------------------------------------------- */
double closestPair(std::vector<Point> const& points)
{
    const size_t n = points.size();
    if (n < 2)
        return 0.0;

    /* Work on a copy sorted by x, followed by a second array
       sorted by y during the recursive steps. */
    std::vector<Point> Px(points), Py(points);
    std::sort(Px.begin(), Px.end(),
              [](const Point& a, const Point& b){ return a.x < b.x; });

    std::sort(Py.begin(), Py.end(),
              [](const Point& a, const Point& b){ return a.y < b.y; });

    /* Recursive helper */
    std::function<double(size_t, size_t)> rec = [&](size_t l, size_t r) -> double
    {
        const size_t len = r - l;
        if (len <= 3) {
            /* Brute force with OpenMP parallelism for tiny blocks */
            double d = std::numeric_limits<double>::max();
#pragma omp parallel for reduction(min : d)
            for (size_t i = l; i < r; ++i) {
                for (size_t j = i + 1; j < r; ++j) {
                    double d2 = dist(Px[i], Px[j]);
                    if (d2 < d) d = d2;
                }
            }
            return d;
        }

        size_t m = l + len / 2;
        double midx = Px[m].x;
        /* Partition Py into left and right halves */
        std::vector<Point> leftY, rightY;
        leftY.reserve(m - l);
        rightY.reserve(r - m);
        for (const auto& p : Py)
        {
            if (p.x <= midx) leftY.push_back(p);
            else             rightY.push_back(p);
        }

        double dl = rec(l, m);
        double dr = rec(m, r);
        double d  = std::min(dl, dr);

        /* Build strip of points within d of the median line */
        std::vector<Point> strip;
        strip.reserve(Py.size());
        for (const auto& p : Py) {
            if (std::fabs(p.x - midx) < d)
                strip.push_back(p);
        }

        /* Check only up to 7 following points per point in the strip */
        const size_t sz = strip.size();
        for (size_t i = 0; i < sz; ++i) {
            for (size_t j = i + 1; j < sz && (strip[j].y - strip[i].y) < d; ++j) {
                double d2 = dist(strip[i], strip[j]);
                if (d2 < d) d = d2;
            }
        }
        return d;
    };

    return rec(0, n);
}
