#pragma once
#include <vector>
#include <algorithm>

/*
 * Sorts the non‑zero elements of the vector in ascending order while leaving
 * the zero elements in their original positions.
 *
 * The implementation first counts the non‑zero entries so that the temporary
 * buffer can be allocated with the exact size required.  It then copies
 * the non‑zero values, sorts them, and finally writes them back in place.
 * This keeps the complexity O(n log m) where *m* is the number of non‑zero
 * elements, and it avoids any unnecessary reallocations.
 */
inline void sortIgnoreZero(std::vector<int> &x)
{
    const std::size_t n = x.size();

    // 1) Count non‑zero elements
    std::size_t nz = 0;
    for (std::size_t i = 0; i < n; ++i)
        if (x[i] != 0)
            ++nz;

    if (nz == 0 || nz == 1)      // nothing to do
        return;

    // 2) Copy non‑zero values to a dedicated buffer
    std::vector<int> buf;
    buf.reserve(nz);
    for (int val : x)
        if (val != 0)
            buf.push_back(val);

    // 3) Sort the buffer
    std::sort(buf.begin(), buf.end());

    // 4) Write the sorted values back into the original vector
    std::size_t idx = 0;
    for (std::size_t i = 0; i < n; ++i)
        if (x[i] != 0)
            x[i] = buf[idx++];
}
