#ifndef M_PI
#define M_PI 3.14159265358979323846
#endif

// ------- In‑place radix‑2 Cooley‑Tukey FFT ---------------------------------
static inline void fft_helper(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    const std::size_t logN = static_cast<std::size_t>(std::log2(static_cast<double>(N)));

    // --- Butterfly stages ----------------------------------------------------
    double step = M_PI / static_cast<double>(N);
    std::complex<double> w = std::complex<double>(std::cos(step), -std::sin(step));

    for (std::size_t m = 1; m < N; m <<= 1)
    {
        std::complex<double> wm = w;
        w = w * w;                          // (e^{-jπ/N})^{2m}
        std::complex<double> t{1.0, 0.0};

        for (std::size_t j = 0; j < m; ++j)
        {
            for (std::size_t i = j; i < N; i += (m << 1))
            {
                const std::complex<double> tmp = x[i] - x[i + m];
                x[i] += x[i + m];
                x[i + m] = tmp * t;
            }
            t *= wm;
        }
    }

    // --- Bit‑reversal permutation -------------------------------------------
    // The length of x is a power of two, so the reverse can be done with
    // a simple mask‑based method.  The following code keeps the exact
    // behaviour of the original implementation.
    for (std::size_t i = 0; i < N; ++i)
    {
        std::size_t rev = i;
        rev  = ((rev & 0xaaaaaaaau) >> 1) | ((rev & 0x55555555u) << 1);
        rev  = ((rev & 0xccccccccu) >> 2) | ((rev & 0x33333333u) << 2);
        rev  = ((rev & 0xf0f0f0f0u) >> 4) | ((rev & 0x0f0f0f0fu) << 4);
        rev  = ((rev & 0xff00ff00u) >> 8) | ((rev & 0x00ff00ffu) << 8);
        rev  = ((rev >> 16) | (rev << 16)) >> (32 - logN);

        if (rev > i)
            std::swap(x[i], x[rev]);
    }
}

// ------- Inverse FFT ---------------------------------------------------------
inline void ifft(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N == 0) return;

    // 1. Conjugate the data
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(N); ++i)
        x[static_cast<std::size_t>(i)] = std::conj(x[static_cast<std::size_t>(i)]);

    // 2. Forward FFT
    fft_helper(x);

    // 3. Conjugate again
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(N); ++i)
        x[static_cast<std::size_t>(i)] = std::conj(x[static_cast<std::size_t>(i)]);

    // 4. Scale by 1/N
    const double invN = 1.0 / static_cast<double>(N);
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(N); ++i)
        x[static_cast<std::size_t>(i)] *= invN;
}
