/* Sort the vector x of complex numbers by their magnitude in ascending order.
   Example:

   input: [3.0-1.0i, 4.5+2.1i, 0.0-1.0i, 1.0-0.0i, 0.5+0.5i]
   output: [0.5+0.5i, 0.0-1.0i, 1.0-0.0i, 3.0-1.0i, 4.5+2.1i]
*/
inline void sortComplexByMagnitude(std::vector<std::complex<double>>& x)
{
    const std::size_t n = x.size();
    if (n <= 1) return;

    // Pre‑compute the squared magnitude (norm) of each element to avoid repeated sqrt calls.
    std::vector<double> mags(n);
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i)
        mags[i] = std::norm(x[i]);   // norm = |x|^2

    // Create an index array and sort it by the precomputed magnitudes.
    std::vector<std::size_t> idx(n);
    std::iota(idx.begin(), idx.end(), 0);
    std::sort(idx.begin(), idx.end(),
              [&](std::size_t a, std::size_t b) { return mags[a] < mags[b]; });

    // Reorder the original vector according to the sorted indices.
    std::vector<std::complex<double>> tmp(n);
    for (std::size_t i = 0; i < n; ++i)
        tmp[i] = x[idx[i]];
    x.swap(tmp);
}
