static const int edgeKernel[3][3] = {
    { -1, -1, -1 },
    { -1,  8, -1 },
    { -1, -1, -1 }
};

/*
 * Convolve the edge kernel with a grayscale image.
 *
 * imageIn  –  NxN image stored in row‑major order (input, immutable).
 * imageOut –  NxN image stored in row‑major order (output, mutable).
 * N        –  dimension of the image.
 *
 * The algorithm is numerically identical to the provided reference
 * implementation but uses OpenMP to parallelise the two outer loops.
 * Bounds checks are eliminated by treating the boundaries as zero
 * weight and by computing the wrapped indices only once per pixel.
 */
inline void convolveKernel(const std::vector<int> &imageIn,
                           std::vector<int> &imageOut,
                           size_t N)
{
    // In a situation where N == 0 the function should be a no‑op.
    if (N == 0 || imageIn.size() < N * N || imageOut.size() < N * N)
        return;

    const int stride = static_cast<int>(N);

    #pragma omp parallel for collapse(2)
    for (int i = 0; i < static_cast<int>(N); ++i) {
        const int base = i * stride;
        for (int j = 0; j < static_cast<int>(N); ++j) {
            int sum = 0;

            // Manually unroll the 3×3 neighbourhood.
            // The zero‑padding outside the image is handled by
            // ignoring contributions when the neighbour is out of bounds.
            // This removes the need for a bounds‑check inside the innermost loop.

            // Top row : i-1
            if (i > 0) {
                const int top = (i - 1) * stride;
                if (j > 0)    sum += imageIn[top + (j - 1)] * edgeKernel[0][0];
                sum        += imageIn[top +  j    ] * edgeKernel[0][1];
                if (j + 1 < static_cast<int>(N))
                    sum += imageIn[top + (j + 1)] * edgeKernel[0][2];
            } else {
                // All neighbours above the image are zero
                // (no contribution needed)
            }

            // Middle row : i
            const int mid = base;
            if (j > 0)    sum += imageIn[mid + (j - 1)] * edgeKernel[1][0];
            sum        += imageIn[mid +  j    ] * edgeKernel[1][1];
            if (j + 1 < static_cast<int>(N))
                sum += imageIn[mid + (j + 1)] * edgeKernel[1][2];

            // Bottom row : i+1
            if (i + 1 < static_cast<int>(N)) {
                const int bot = (i + 1) * stride;
                if (j > 0)    sum += imageIn[bot + (j - 1)] * edgeKernel[2][0];
                sum        += imageIn[bot +  j    ] * edgeKernel[2][1];
                if (j + 1 < static_cast<int>(N))
                    sum += imageIn[bot + (j + 1)] * edgeKernel[2][2];
            }

            // Clamp to [0,255]
            imageOut[base + j] = static_cast<int>(std::min(255, std::max(0, sum)));
        }
    }
}
