/*
 * Solve the linear system Ax = b for x.
 * A is an NxN matrix stored in row‑major order.  x and b are length N.
 *
 * The implementation performs a straightforward Gaussian elimination with
 * partial pivoting (no row swaps are performed, because the original
 * algorithm also never swapped).  The algorithm is cache‑friendly and
 * uses OpenMP to parallelise the row reductions.
 *
 * Parameters
 * ---------
 *   A   - Input matrix (read‑only, row‑major).
 *   b   - Right‑hand side vector (read‑only).
 *   x   - Output vector containing the solution.
 *   N   - The dimension of the system.
 *
 * The function preserves the exact numeric behaviour of the reference
 * implementation: it makes a copy of the inputs, returns immediately if a
 * zero pivot is encountered, and does not perform any row interchanges.
 *
 * Complexity
 * -----------
 *   O(N³) time, O(N²) memory for the copy of A.
 */
inline void solveLinearSystem(
    const std::vector<double>& A,
    const std::vector<double>& b,
    std::vector<double>& x,
    const size_t N)
{
    // Fast-path for trivial systems
    if (N == 0) return;
    if (N == 1) {
        x[0] = b[0] / A[0];
        return;
    }

    // Allocate a contiguous copy of the matrix and RHS
    std::vector<double> Acopy(A);          // copy of A (row‑major)
    std::vector<double> bcopy(b);           // copy of b

    // ----------------------------------------------------
    // 1) Forward elimination – parallelised row updates
    // ----------------------------------------------------
    for (size_t i = 0; i < N - 1; ++i) {
        const double pivot = Acopy[i * N + i];
        if (pivot == 0.0)  // zero pivot: numerical failure, leave x untouched
            return;

        // Parameters for the inner loop
        const size_t rowStart = i + 1;
        const size_t cols = N - i;

        // Parallelise the elimination of rows below the pivot row.
        // A is stored row‑major; each thread works on independent rows.
#pragma omp parallel for schedule(static)
        for (long long jj = static_cast<long long>(rowStart); jj < static_cast<long long>(N); ++jj) {
            const size_t j = static_cast<size_t>(jj);
            const double factor = Acopy[j * N + i] / pivot;
            if (factor == 0.0) continue;              // Nothing to do

            // Update all columns from i to N-1 in the target row.
            double* target = &Acopy[j * N + i];
            const double* pivotRow = &Acopy[i * N + i];
            for (size_t k = 0; k < cols; ++k)
                *(target + k) -= factor * *(pivotRow + k);

            // Update the RHS
            bcopy[j] -= factor * bcopy[i];
        }
    }

    // ----------------------------------------------------
    // 2) Back substitution – scalar
    // ----------------------------------------------------
    // The back‑substitution phase requires the results of previous rows,
    // so it is kept serial for simplicity and correctness.
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        const double* row = &Acopy[i * N + i + 1];
        for (size_t j = i + 1; j < N; ++j)
            sum += row[j - i - 1] * x[j];
        x[i] = (bcopy[i] - sum) / Acopy[i * N + i];
    }
}
