/*
 *  LU factorization (in-place, row-major storage).
 *  The matrix A is overwritten with the L and U factors.
 *  L has unit diagonal (implicit, not stored).
 */
void luFactorize(std::vector<double> &A, std::size_t N)
{
    double *a = A.data();

    for (std::size_t k = 0; k < N; ++k)
    {
        const double pivot = a[k * N + k];
        /* All rows below the pivot can be processed in parallel because
         * they depend only on the current column k. */
        #pragma omp parallel for schedule(static, 64)
        for (std::size_t i = k + 1; i < N; ++i)
        {
            const double factor = a[i * N + k] / pivot;
            a[i * N + k] = factor;

            /* pointer to the first element after the pivot in the two rows */
            double *row_i = a + i * N + k + 1;
            double *row_k = a + k * N + k + 1;
            std::size_t remaining = N - (k + 1);

            /* vectorised loop, unrolled by 4 */
            std::size_t j = 0;
            for (; j + 4 <= remaining; j += 4)
            {
                row_i[0] -= factor * row_k[0];
                row_i[1] -= factor * row_k[1];
                row_i[2] -= factor * row_k[2];
                row_i[3] -= factor * row_k[3];
                row_i += 4;
                row_k += 4;
            }
            /* remaining elements */
            for (; j < remaining; ++j)
            {
                *row_i -= factor * (*row_k);
                ++row_i;
                ++row_k;
            }
        }
    }
}
