#pragma once
#include <vector>
#include <cstddef>
#include <cstdint>
#include <immintrin.h>   // AVX2 intrinsics
#include <omp.h>

// -----------------------------------------------------------------------------
// findFirstEven: find the index of the first even element in a std::vector<int>.
// The function is fully functional and preserves the exact behaviour of the
// original implementation while exploiting SIMD and parallelism where it
// makes a measurable difference on typical x86‑64 hardware.
//
// Performance notes:
//   * Uses AVX2 256‑bit registers to scan 8 ints at a time.
//   * Works correctly on arbitrary vector sizes (including those not
//     divisible by 8).
//   * Falls back to a simple scalar loop for very small inputs.
//   * The function is thread‑safe – it only reads from the input vector.
//   * No data races because the function never writes to the vector.
//   * The return value is the index of the first even element, or
//     x.size() if none exists.
//
// -----------------------------------------------------------------------------
// Helper to test a word of 8 ints for the presence of an even number.
inline bool any_even_v8i32(__m256i v)
{
    // Evenness is determined by the least‑significant bit.
    // Even numbers have bit 0 == 0, therefore we check if
    // (v & 1) == 0 for any lane.
    const __m256i one  = _mm256_set1_epi32(1);
    const __m256i mask = _mm256_and_si256(v, one);     // bit 0 of each lane
    const __m256i zero = _mm256_setzero_si256();
    return _mm256_movemask_epi8(_mm256_cmpeq_epi32(mask, zero)) != 0;
}

// Core implementation
size_t findFirstEven(std::vector<int> const& x)
{
    const size_t N = x.size();
    constexpr size_t lane = 8;                       // 8 ints per AVX2 register
    const size_t stride = lane * 4;                  // 32 bytes

    // For very small vectors the overhead of intrinsics is significant.
    if (N < 32) {
        for (size_t i = 0; i < N; ++i)
            if ((x[i] & 1) == 0)
                return i;
        return N;
    }

    // Scan chunks of 256 bits in parallel.
    size_t i = 0;
    for (; i + 8 <= N; i += 8) {
        __m256i reg = _mm256_loadu_si256(reinterpret_cast<const __m256i*>(&x[i]));
        if (any_even_v8i32(reg)) {
            // There is at least one even value – find the first.
            for (size_t j = 0; j < lane; ++j) {
                if ((x[i + j] & 1) == 0)
                    return i + j;
            }
        }
    }

    // Remainder (at most 7 ints) – scalar fallback.
    for (; i < N; ++i)
        if ((x[i] & 1) == 0)
            return i;

    return N;   // No even numbers found
}
