#pragma once
#include <vector>
#include <algorithm>
#include <omp.h>

struct Element {
    size_t index;
    double value;
};

/* Compute z = alpha*x+y where x and y are sparse vectors. Store the result in z.
   Example:

   input: x=[{5, 12}, {8, 3}, {12, -1}], y=[{3, 1}, {5, -2}, {7, 1}, {8, -3}], alpha=1
   output: z=[{3, 1}, {5, 10}, {7, 1}, {12, -1}]
*/
void sparseAxpy(double alpha,
                std::vector<Element> const& x,
                std::vector<Element> const& y,
                std::vector<double> &z)
{
    const size_t nx = x.size();
    const size_t ny = y.size();

    if (ny == 0) {                      // only x
        #pragma omp parallel for schedule(static)
        for (size_t i = 0; i < nx; ++i)
            z[x[i].index] += alpha * x[i].value;
        return;
    }
    if (nx == 0) {                      // only y
        #pragma omp parallel for schedule(static)
        for (size_t i = 0; i < ny; ++i)
            z[y[i].index] += y[i].value;
        return;
    }

    /* Partition the y vector into chunks processed independently by each thread.
       Indices in y are sorted, and each chunk receives a contiguous index range
       that guarantees no two threads will write to the same z entry. */

    const int nthreads = omp_get_max_threads();
    std::vector<size_t> y_start(nthreads + 1);
    const size_t chunk = (ny + nthreads - 1) / nthreads;
    for (int t = 0; t <= nthreads; ++t)
        y_start[t] = std::min< size_t >(t * chunk, ny);

    #pragma omp parallel num_threads(nthreads)
    {
        int t = omp_get_thread_num();
        size_t ys = y_start[t];
        size_t ye = y_start[t + 1];
        if (ys == ye) return;          // empty chunk

        /* Find the first element of x that could be merged with the
           first element of this y chunk. */
        size_t xi = std::lower_bound(x.begin(), x.end(), y[ys].index,
                                     [](const Element& e, size_t idx){ return e.index < idx; })
                    - x.begin();

        /* Merge this y chunk with the relevant slice of x. */
        for (size_t yi = ys; yi < ye; ++yi) {
            while (xi < nx && x[xi].index < y[yi].index) {
                z[x[xi].index] += alpha * x[xi].value;
                ++xi;
            }
            if (xi < nx && x[xi].index == y[yi].index) {
                z[x[xi].index] += alpha * x[xi].value + y[yi].value;
                ++xi;
            } else {
                z[y[yi].index] += y[yi].value;
            }
        }

        /* Process any remaining x elements that still belong to this chunk
           but are beyond its last y index. */
        if (yi < ye) {
            const size_t lastY = y[ye - 1].index;
            for (; xi < nx && x[xi].index <= lastY; ++xi) {
                z[x[xi].index] += alpha * x[xi].value;
            }
        }

        /* The last thread processes the tail of x that lies beyond all y elements. */
        if (t == nthreads - 1) {
            for (; xi < nx; ++xi) {
                z[x[xi].index] += alpha * x[xi].value;
            }
        }
    }
}
