/*
 *  Highly‑optimized radix‑4 FFT with conjugation
 *
 *  Features
 *    ・Iterative Cooley‑Tukey algorithm (size = power of two)
 *    ・Stride‑length 4 butterflies (radix‑4) for speed
 *    ・Pre‑computed sin/cos tables
 *    ・OpenMP parallelisation over outer stages
 *    ・In‑place bit‑reversal using bit‑twiddling
 *
 *  The original behaviour is preserved – the function rotates the
 *  spectrum to the frequency‑domain and then takes the complex
 *  conjugate of every coefficient.
 */
#pragma once

#include <vector>
#include <complex>
#include <cmath>
#include <cstdint>
#include <omp.h>

/* ---------- Helper: compute number of stages (log2) ---------- */
inline unsigned int log2_floor(uint32_t n) {
    return 31 - __builtin_clz(n);
}

/* ---------- Pre‑compute sinusoid table (twiddle factors) ---------- */
static void precompute_twiddles(std::vector<std::complex<double>>& wav, unsigned int n) {
    wav.resize(n / 2);
    const double pi = 3.14159265358979323846264338327950288;
    for (unsigned int k = 0; k < n / 2; ++k)
        wav[k] = std::polar(1.0, -2 * pi * k / n);   // exp(-i*2*pi*k/n)
}

/* ---------- In‑place radix‑4 butterfly ---------- */
inline void butterfly(std::complex<double> *x, unsigned int i, unsigned int m,
                      const std::complex<double> &t0, const std::complex<double> &t1,
                      const std::complex<double> &t2)
{
    std::complex<double> a0 = x[i],     a1 = x[i + m];
    std::complex<double> a2 = x[i + 2*m], a3 = x[i + 3*m];

    std::complex<double> b0 = a0 + a2;
    std::complex<double> b1 = a1 + a3;
    std::complex<double> b2 = a0 - a2;
    std::complex<double> b3 = a1 - a3;

    x[i]         = b0 + b1;
    x[i + m]     = (b0 - b1) * t0;
    x[i + 2*m]   = (b2 + b3 * std::complex<double>(0, 1)) * t1;
    x[i + 3*m]   = (b2 - b3 * std::complex<double>(0, 1)) * t2;
}

/* ---------- Bit‑reversal using 32‑bit meta‑operations (fast) ---------- */
inline uint32_t bit_reverse(uint32_t v, unsigned int bits) {
    v = ((v & 0x55555555u) << 1) | ((v >> 1) & 0x55555555u);
    v = ((v & 0x33333333u) << 2) | ((v >> 2) & 0x33333333u);
    v = ((v & 0x0f0f0f0fu) << 4) | ((v >> 4) & 0x0f0f0f0fu);
    v = ((v & 0x00ff00ffu) << 8) | ((v >> 8) & 0x00ff00ffu);
    v = (v << 16) | (v >> 16);
    return v >> (32 - bits);
}

/* ---------- Main FFT with conjugation ---------- */
inline void fftConjugate(std::vector<std::complex<double>>& x) {
    const unsigned int N = static_cast<unsigned int>(x.size());
    if (N < 2) return;                                   // nothing to do

    /* ---- Stage 0 : pre‑interleave (radix‑4) ---- */
    // swap elements 0 <-> N/2, 1<->N/2+1, ...
    for (uint32_t i = 0; i < N / 2; ++i)
        std::swap(x[i], x[i + N / 2]);

    /* ---- Pre‑compute twiddle tables for each stage ---- */
    std::vector<std::vector<std::complex<double>>> twiddles;
    unsigned int stages = log2_floor(N);
    twiddles.resize((stages + 1) / 2);        // we use radix‑4, so every 2 stages share a table

    unsigned int n = N;
    for (size_t s = 0; s < twiddles.size(); ++s) {
        precompute_twiddles(twiddles[s], n);
        n >>= 2;
    }

    /* ---- Radix‑4 FFT iterations ---- */
    n = N;
    unsigned int stage = 0;
    size_t twiddleIdx = 0;
    for (stage = 0; stage < stages; ++stage) {
        if ((stage & 1) == 0) {                    // even stage – prepare twiddles
            // no action needed; table is already ready
            ++twiddleIdx;
        }
    }

    n = N;
    for (unsigned int s = 0; s < stages; ++s) {
        const std::complex<double>* W = twiddles[s >> 1].data(); // stride: 1,2,4,8...
        unsigned int m = 1U << (s & 1);         // 1,2,4,...
        unsigned int step = n / 4;

        #pragma omp parallel for schedule(static)
        for (uint32_t i = 0; i < n; i += step * 4) {
            for (uint32_t j = i; j < i + step; ++j) {
                unsigned int k = j / step;        // 0..(N/4)-1
                std::complex<double> t0 = W[(k * 2) % (n/2)];
                std::complex<double> t1 = W[(k * 6) % (n/2)];
                std::complex<double> t2 = W[(k * 10) % (n/2)];
                butterfly(&x[j], 0, m, t0, t1, t2);
            }
        }

        n >>= 1;   // stage effective size for next round
    }

    /* ---- Bit‑reversal ---- */
    unsigned int bits = stages;
    for (uint32_t i = 0; i < N; ++i) {
        uint32_t j = bit_reverse(i, bits);
        if (j > i) std::swap(x[i], x[j]);
    }

    /* ---- Final conjugate ---- */
    #pragma omp parallel for schedule(static)
    for (uint32_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);
}
